    [cte_formula_38] AS (
        -- !!! STUB — requires manual review !!!
        SELECT
            *,
            CASE WHEN MONTH([timestamp]) > 7 THEN CAST(YEAR([timestamp]) AS VARCHAR(4)) + '/' + CAST(YEAR([timestamp]) + 1 AS VARCHAR(4)) ELSE CAST(YEAR([timestamp]) - 1 AS VARCHAR(4)) + '/' + CAST(YEAR([timestamp]) AS VARCHAR(4)) END AS [SchoolYear],
