            CASE [mainUserGroup]
            WHEN '3' THEN 'Studerende'
            WHEN '21' THEN 'Valideret lærer'
            WHEN '2' THEN 'Lærere'
            WHEN '4' THEN 'Private'
            ELSE 'NA'
        END AS [MainUserType],
