    [cte_union_67] AS (
        -- UNION ALL preserves duplicates. Change to UNION to deduplicate.
        SELECT * FROM [cte_select_44]
        UNION ALL
        SELECT * FROM [cte_text_input_66]
    ),
    
    [cte_formula_12] AS (
        SELECT
            *,
            CASE 
            WHEN [UserSubject] IN ('eud/eux', 'eud/eux/kuu') THEN 'eud/eux'
            WHEN [UserSubject] IN ('Andet', 'N/A', 'Not set') THEN 'Andet'
            WHEN [UserSubject] = 'avu/fvu/obu/fgu' THEN 'avu/fvu/du/fgu'
            WHEN [UserSubject] IS NULL OR [UserSubject] = '' THEN 'Andet'
            ELSE [UserSubject]
        END AS [UserSubject]
        FROM [cte_record_id_20]
    ),
    
    [cte_join_4] AS (
        -- !!! STUB — requires manual review !!!
        -- Join anchor output (matched rows)
        -- Left-only:  add WHERE R.[logged_hostname] IS NULL
        -- Right-only: add WHERE L.[hostname] IS NULL
        SELECT
            L.[UserSubject],
            L.[eKeysUser],
            L.[hostname],
            L.[isbn],
            L.[companyId],
            L.[groupIds],
            L.[pageId],
            L.[mainUserGroup],
            L.[firstLevelLog],
            L.[rootLineString],
            L.[featureFlags],
            L.[myAccountId],
            L.[queryParamsEncoded],
            L.[customerId],
            L.[timestamp],
            L.[id],
            L.[importFilename],
            L.[SchoolYear],
            L.[Date],
            L.[MainUserType],
            L.[PageViews],
            L.[ops_varenummer],
            L.[RecordID],
            R.[logged_varenummer],
            R.[alter_varenummer],
            [hashedUserid],
            [mainUserSubject]
        FROM [cte_formula_12] AS L
        INNER JOIN [cte_select_6] AS R
            ON L.[hostname] = R.[logged_hostname]
            AND L.[ops_varenummer] = R.[logged_varenummer]
    ),
    
    [cte_filter_17] AS (
