    [cte_union_16] AS (
        -- UNION ALL preserves duplicates. Change to UNION to deduplicate.
        SELECT * FROM [cte_filter_17_to_select_18]
        UNION ALL
        SELECT * FROM [cte_join_4]
    ),
    
    [cte_unique_19] AS (
        -- Unique anchor: first occurrence per key
        -- For duplicates anchor: change WHERE _rn = 1 to WHERE _rn > 1
        SELECT *
        FROM (
            SELECT
                *,
                ROW_NUMBER() OVER (
                    PARTITION BY [RecordID]
                    ORDER BY (SELECT NULL)
                ) AS _rn
            FROM [cte_union_16]
        ) AS _deduped
        WHERE _rn = 1
    ),
    
    [cte_union_16_to_filter_69] AS (
