        FROM [cte_union_16_to_filter_69]
    ),
    
    [cte_formula_53] AS (
        -- !!! STUB — requires manual review !!!
        SELECT
            *,
            CASE 
            WHEN [myAccountId] = 'STUDYBOXMYACCOUNT' AND [customerId] IN ('Munksgaard', 'Hans Reitzel') THEN 'StudyBox'
            WHEN [myAccountId] = 'STUDYBOXMYACCOUNT' THEN 'Other StudyBox'
            ELSE [customerId] 
        END AS [Publisher]
        FROM [cte_union_16_to_filter_69]
    ),
    
    [cte_summarize_39] AS (
        -- !!! STUB — requires manual review !!!
        SELECT
