    [cte_formula_85] AS (
        -- !!! STUB — requires manual review !!!
        SELECT
            *,
            CASE 
            WHEN [PublisherERP] = 'Dansklærerforeningen & Systime' AND [Publisher] = 'Systime' THEN 'Dansklærerforeningen & Systime'
            WHEN [PublisherERP] = 'Dansklærerforeningens Forlag' AND [Publisher] = 'Dlf' THEN 'Dansklærerforeningens Forlag'
            WHEN [PublisherERP] = 'DlfF Forlag' AND [Publisher] = 'Systime' THEN 'Systime'
            WHEN [PublisherERP] = 'FNAE' AND [Publisher] = 'Systime' THEN 'Systime'
            WHEN [PublisherERP] = 'Forlaget Columbus' AND [Publisher] = 'Columbus' THEN 'Forlaget Columbus'
            WHEN [PublisherERP] = 'GU Gym' AND [Publisher] = 'Gyldendal' THEN 'Gyldendal'
            WHEN [PublisherERP] = 'GU Sys' AND [Publisher] = 'Systime' THEN 'Systime'
            WHEN [PublisherERP] = 'Gyldendal' AND [Publisher] = 'Gyldendal-voksen' THEN 'Gyldendal'
            WHEN [PublisherERP] = 'Hans Reitzel' AND [Publisher] = 'Munksgaard' THEN 'Munksgaard'
            WHEN [PublisherERP] = 'Hans Reitzel' AND [Publisher] = 'Systime' THEN 'Systime'
            WHEN [PublisherERP] = 'Gyldendal' AND [Publisher] = 'Systime' THEN 'Systime'
            WHEN [PublisherERP] = 'Systime' AND [Publisher] = 'Systimesolutions' THEN 'Systimesolutions'
            WHEN [PublisherERP] = 'Systime/Hans Reitzel' AND [Publisher] = 'Hansreitzel' THEN 'Hans Reitzel'
            WHEN [PublisherERP] = 'Systime/Hans Reitzel' AND [Publisher] = 'Systime' THEN 'Systime'
            WHEN [PublisherERP] = 'GU Gym' THEN 'Gyldendal'
            WHEN [PublisherERP] = 'GU Sys' THEN 'Systime'
            WHEN [PublisherERP] = 'VIA-Systime' THEN 'Systime'
            WHEN [PublisherERP] = 'Kurlund' THEN 'Systime'
            WHEN [PublisherERP] = 'DlfF Forlag' THEN 'Dansklærerforeningen & Systime'
            ELSE [PublisherERP]
        END AS [Publisher_Final]
        FROM [cte_union_78]
    ),
    
